import{_ as a,C as e,o as r,c as i,E as s,a3 as o}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"六十甲子","description":"十天干 × 十二地支 = 六十甲子。六十年一轮回，纪年纪月纪日纪时的底层系统。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"六十甲子","description":"十天干 × 十二地支 = 六十甲子。六十年一轮回，纪年纪月纪日纪时的底层系统。"},"headers":[],"relativePath":"changshi/tiangan-dizhi/liushi-jiazi.md","filePath":"changshi/tiangan-dizhi/liushi-jiazi.md","lastUpdated":1779783531000}'),n={name:"changshi/tiangan-dizhi/liushi-jiazi.md"};function h(l,t,p,c,b,g){const d=e("SixtyJiazi");return r(),i("div",null,[s(d),t[0]||(t[0]=o(`<h2 id="为什么是-60-不是-120" tabindex="-1">为什么是 60，不是 120？ <a class="header-anchor" href="#为什么是-60-不是-120" aria-label="Permalink to &quot;为什么是 60，不是 120？&quot;">​</a></h2><p>天干 10 个，地支 12 个，若全部组合应得 120 种——但有一条铁律：</p><blockquote><p><strong>阳干只配阳支，阴干只配阴支</strong></p></blockquote><table tabindex="0"><thead><tr><th></th><th>天干</th><th>地支</th><th>组合</th></tr></thead><tbody><tr><td>阳</td><td>甲丙戊庚壬（5个）</td><td>子寅辰午申戌（6个）</td><td>5×6 = 30</td></tr><tr><td>阴</td><td>乙丁己辛癸（5个）</td><td>丑卯巳未酉亥（6个）</td><td>5×6 = 30</td></tr><tr><td><strong>合计</strong></td><td></td><td></td><td><strong>60</strong></td></tr></tbody></table><h2 id="公历年份-→-干支快速推算" tabindex="-1">公历年份 → 干支快速推算 <a class="header-anchor" href="#公历年份-→-干支快速推算" aria-label="Permalink to &quot;公历年份 → 干支快速推算&quot;">​</a></h2><p>以 <strong>1984年 = 甲子年</strong> 为锚点：</p><ul><li>天干序号 = (年份 − 1984) mod 10（负数加10，结果0取10）</li><li>地支序号 = (年份 − 1984) mod 12（负数加12，结果0取12）</li></ul><table tabindex="0"><thead><tr><th>年份</th><th>天干</th><th>地支</th><th>干支年</th></tr></thead><tbody><tr><td>1984</td><td>甲(1)</td><td>子(1)</td><td>甲子</td></tr><tr><td>2000</td><td>庚(7)</td><td>辰(5)</td><td>庚辰</td></tr><tr><td>2024</td><td>甲(1)</td><td>辰(5)</td><td>甲辰</td></tr><tr><td>2025</td><td>乙(2)</td><td>巳(6)</td><td>乙巳</td></tr><tr><td><strong>2026</strong></td><td><strong>丙(3)</strong></td><td><strong>午(7)</strong></td><td><strong>丙午</strong></td></tr></tbody></table><h2 id="相邻干支的跳跃规律" tabindex="-1">相邻干支的跳跃规律 <a class="header-anchor" href="#相邻干支的跳跃规律" aria-label="Permalink to &quot;相邻干支的跳跃规律&quot;">​</a></h2><p>每往后 10 步：天干回到原位，地支前进了 10 格（差 2 格退回）。</p><blockquote><p>同一天干的两次出现，地支相差 −2 位（逢 10 必差 2）</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>甲子 → 甲戌（差10，地支子→戌退2）</span></span>
<span class="line"><span>甲戌 → 甲申 → 甲午 → 甲辰 → 甲寅 → 回到甲子（共6次，6×10=60）</span></span></code></pre></div><h2 id="六组·十年段结构" tabindex="-1">六组·十年段结构 <a class="header-anchor" href="#六组·十年段结构" aria-label="Permalink to &quot;六组·十年段结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组</th><th>起始</th><th>结束</th><th>地支起</th></tr></thead><tbody><tr><td>1</td><td>甲子</td><td>癸酉</td><td>子(1)</td></tr><tr><td>2</td><td>甲戌</td><td>癸未</td><td>戌(11)</td></tr><tr><td>3</td><td>甲申</td><td>癸巳</td><td>申(9)</td></tr><tr><td>4</td><td>甲午</td><td>癸卯</td><td>午(7)</td></tr><tr><td>5</td><td>甲辰</td><td>癸丑</td><td>辰(5)</td></tr><tr><td>6</td><td>甲寅</td><td>癸亥</td><td>寅(3)</td></tr></tbody></table><p>每组地支起点退 2 位，6 组后恰好循环。</p>`,15))])}const m=a(n,[["render",h]]);export{_ as __pageData,m as default};
